// generar_266_hitos_permanentes_y_enriquecimiento_ui.js
// CHIQUI Entre Señales — Hitos permanentes en el calendario +
// Enriquecimiento desplegable con Chiqui
//
// Tres mejoras:
//
// 1) HITOS QUE NO SE BORRAN DE UN TOQUE (registro diario)
//    Antes: tocar un hito ya logrado lo eliminaba al instante, desde
//    cualquier día. Un roce accidental borraba la fecha de un recuerdo
//    único.
//    Ahora: tocar un hito logrado NO lo borra — abre una tarjeta que
//    muestra cuándo se registró ("✓ 15 de julio de 2026") con el
//    mensaje "Este momento queda guardado para siempre 💛" y un botón
//    "Entendido". Debajo, en letra pequeña, "¿Lo registraste por
//    error? Corregir" abre la confirmación con botón rojo explícito.
//    Se mantiene la edición (indispensable para errores de dedo o
//    fecha equivocada), pero deja de ser accidental.
//
// 2) HITOS EN EL CALENDARIO
//    · Los días con un hito muestran una huella dorada 🐾 en la
//      esquina de la celda — distinta de los puntos de cuidados,
//      porque un hito es un momento único y no una rutina.
//    · Al abrir el día, arriba de todo aparece "🐾 Hito de este día"
//      con la tarjeta dorada y el nombre del logro. Se muestra
//      SIEMPRE, aunque ese día no tenga registro diario (un hito
//      puede registrarse solo).
//
// 3) ENRIQUECIMIENTO EN ANÁLISIS: ícono y desplegable
//    · El emoji 🧠 se reemplaza por la ilustración de Chiqui con el
//      Kong (chiqui_juguetes.png), como el resto de las secciones.
//    · La sección ahora es colapsable (cerrada por defecto) con el
//      contador de días con actividad en la cabecera dorada, igual que
//      los grupos de cuidados y las secciones de exámenes.
//
// No hay SQL (usa las tablas del 260, 261 y 262).
//
// Uso:
//   node generar_266_hitos_permanentes_y_enriquecimiento_ui.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/calendario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/analisis/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 3 archivos escritos. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
